INSERT INTO news (id, league_id, team_id, type, headline, body, created_at) VALUES ('110125a7-13cd-4462-b97b-93778088ae53', '7a82b469-d4db-4ee6-b730-2ec85a68122d', '01f283b9-6e9b-42f0-a214-410175a65a96', 'manager_arrival', 'Master Blaster vyhozen — Čkyně hledá kouče, který si pamatuje, kdy je trénink', 'Vedení SK Čkyně se po měsících apatického vedení rozhodlo udělat tlustou čáru: Master Blaster (37, bývalý hráč, poslední dobou převážně bývalý) má padáka. Posledního tréninku se zúčastnilo 12 z 20 chlapů — zbytek sekal trávu do noci, vyklízel stodolu po dědovi, byl na nočce nebo si prostě "myslel, že je trénink zítra". "Když to nebere vážně kouč, proč bysme my?" uvedl pro Hospodský Zpravodaj anonymní záložník.
